using CarCareTracker.External.Interfaces;
using CarCareTracker.Models;
using Npgsql;
using System.Text.Json;

namespace CarCareTracker.External.Implementations
{
    public class PGPushSubscriptionDataAccess : IPushSubscriptionDataAccess
    {
        private NpgsqlDataSource pgDataSource;
        private readonly ILogger<PGPushSubscriptionDataAccess> _logger;
        private static string tableName = "pushsubscriptions";
        public PGPushSubscriptionDataAccess(IConfiguration config, ILogger<PGPushSubscriptionDataAccess> logger)
        {
            pgDataSource = NpgsqlDataSource.Create(config["POSTGRES_CONNECTION"] ?? string.Empty);
            _logger = logger;
            try
            {
                string initCMD = $"CREATE SCHEMA IF NOT EXISTS app; CREATE TABLE IF NOT EXISTS app.{tableName} (id INT GENERATED BY DEFAULT AS IDENTITY primary key, userId INT not null, data jsonb not null)";
                using (var ctext = pgDataSource.CreateCommand(initCMD))
                {
                    ctext.ExecuteNonQuery();
                }
            }
            catch (Exception ex)
            {
                _logger.LogError(ex.Message);
            }
        }
        public List<PushSubscriptionRecord> GetSubscriptionsByUserId(int userId)
        {
            try
            {
                string cmd = $"SELECT data FROM app.{tableName} WHERE userId = @userId";
                var results = new List<PushSubscriptionRecord>();
                using (var ctext = pgDataSource.CreateCommand(cmd))
                {
                    ctext.Parameters.AddWithValue("userId", userId);
                    using (NpgsqlDataReader reader = ctext.ExecuteReader())
                        while (reader.Read())
                            results.Add(JsonSerializer.Deserialize<PushSubscriptionRecord>(reader["data"] as string));
                }
                return results;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex.Message);
                return new List<PushSubscriptionRecord>();
            }
        }
        public bool SaveSubscription(PushSubscriptionRecord subscription)
        {
            try
            {
                // Check if endpoint already exists to upsert
                string checkCmd = $"SELECT id FROM app.{tableName} WHERE data->>'Endpoint' = @endpoint LIMIT 1";
                int existingId = 0;
                using (var ctext = pgDataSource.CreateCommand(checkCmd))
                {
                    ctext.Parameters.AddWithValue("endpoint", subscription.Endpoint);
                    var scalar = ctext.ExecuteScalar();
                    if (scalar != null) existingId = Convert.ToInt32(scalar);
                }
                if (existingId != 0)
                {
                    subscription.Id = existingId;
                    string updateCmd = $"UPDATE app.{tableName} SET data = CAST(@data AS jsonb) WHERE id = @id";
                    using (var ctext = pgDataSource.CreateCommand(updateCmd))
                    {
                        ctext.Parameters.AddWithValue("id", existingId);
                        ctext.Parameters.AddWithValue("data", JsonSerializer.Serialize(subscription));
                        return ctext.ExecuteNonQuery() > 0;
                    }
                }
                else
                {
                    string insertCmd = $"INSERT INTO app.{tableName} (userId, data) VALUES(@userId, CAST(@data AS jsonb)) RETURNING id";
                    using (var ctext = pgDataSource.CreateCommand(insertCmd))
                    {
                        ctext.Parameters.AddWithValue("userId", subscription.UserId);
                        ctext.Parameters.AddWithValue("data", "{}");
                        subscription.Id = Convert.ToInt32(ctext.ExecuteScalar());
                        if (subscription.Id != default)
                        {
                            string updateCmd = $"UPDATE app.{tableName} SET data = CAST(@data AS jsonb) WHERE id = @id";
                            using (var ctextU = pgDataSource.CreateCommand(updateCmd))
                            {
                                ctextU.Parameters.AddWithValue("id", subscription.Id);
                                ctextU.Parameters.AddWithValue("data", JsonSerializer.Serialize(subscription));
                                return ctextU.ExecuteNonQuery() > 0;
                            }
                        }
                        return false;
                    }
                }
            }
            catch (Exception ex)
            {
                _logger.LogError(ex.Message);
                return false;
            }
        }
        public bool DeleteSubscriptionByEndpoint(string endpoint)
        {
            try
            {
                string cmd = $"DELETE FROM app.{tableName} WHERE data->>'Endpoint' = @endpoint";
                using (var ctext = pgDataSource.CreateCommand(cmd))
                {
                    ctext.Parameters.AddWithValue("endpoint", endpoint);
                    return ctext.ExecuteNonQuery() > 0;
                }
            }
            catch (Exception ex)
            {
                _logger.LogError(ex.Message);
                return false;
            }
        }
        public bool DeleteAllSubscriptionsByUserId(int userId)
        {
            try
            {
                string cmd = $"DELETE FROM app.{tableName} WHERE userId = @id";
                using (var ctext = pgDataSource.CreateCommand(cmd))
                {
                    ctext.Parameters.AddWithValue("id", userId);
                    ctext.ExecuteNonQuery();
                    return true;
                }
            }
            catch (Exception ex)
            {
                _logger.LogError(ex.Message);
                return false;
            }
        }
    }
}
